using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerResourceType]
public static class ConfigResources
{
    [McpServerResource(
        UriTemplate = "config://app/settings",
        Name = "App Settings",
        MimeType = "application/json"),
     Description("Returns the current application configuration as JSON.")]
    public static string GetAppSettings() =>
        JsonSerializer.Serialize(new
        {
            Environment = "Production",
            MaxRetries = 3,
            TimeoutSeconds = 30,
            Features = new { DarkMode = true, BetaAccess = false }
        }, new JsonSerializerOptions { WriteIndented = true });

    [McpServerResource(
        UriTemplate = "config://app/version",
        Name = "App Version",
        MimeType = "text/plain"),
     Description("Returns the application version string.")]
    public static string GetVersion() => "1.0.0";
}

using System.ComponentModel;
using ModelContextProtocol.Server;

[McpServerToolType]
public static class GreetingTools
{
    [McpServerTool, Description("Returns a personalized greeting for the given name.")]
    public static string Greet(
        [Description("The person's name to greet")] string name) =>
        $"Hello, {name}! Welcome to the HTTP MCP Server.";
}

